pragma solidity ^0.8.4;

import "@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol";
import "@openzeppelin/consolidation/security/Pausable.sol";
import "@openzeppelin/contracts/access/Ownable.sol";

contract TokenContract is ERC721URIStorage, Pausable, Ownable {
    enum MintState { Genesis, PostGenesis }
    enum WhitelistType { Free, Paid, Public }

    uint256 public constant FREE_WHITELIST_LIMIT = 1000;
    uint256 public constant PAID_WHITELIST_LIMIT = 2000;
    uint256 public constant PUBLIC_MINT_LIMIT = 7000;
    uint256 public totalSupplyLimit = 10000;
    uint256 public freeWhitelistMinted;
    uint256 public paidWhitelistMinted;
    uint256 public publicMinted;
    string public baseURI;
    MintState public currentMintState = MintState.Genesis;
    mapping(address => bool) public freeWhitelist;
    mapping(address => bool) public paidWhitelist;

    event MintStateChanged(MintState newState);
    event EvolvedFromGenesis();
    event TokensRevealed(string newBaseURI);

    modifier onlyFreeWhitelisted() {
        require(freeWhitelist[msg.sender], "Not whitelisted");
        _;
    }

    modifier onlyPaidWhitelisted() {
        require(paidWhitelist[msg.sender], "Not whitelisted");
        _;
    }

    function setBaseURI(string memory _newBaseURI) external onlyOwner {
        baseURI = _newBaseURI;
        emit TokensRevealed(_newBaseURI);
    }

    function setMintState(MintState newState) external onlyOwner {
        require(currentMintState != newState, "New state must be different");
        if (newState == MintState.PostGenesis) {
            require(freeWhitelistMinted >= FREE_WHITELIST_LIMIT, "Not enough free whitelist mints");
        }
        currentMintState = newState;
        emit MintStateChanged(newState);
    }

    function evolveFromGenesis() external onlyOwner {
        require(currentMintState == MintState.Genesis, "Already post-genesis");
        currentMintState = MintState.PostGenesis;
        emit EvolvedFromGenesis();
    }

    function addToFreeWhitelist(address[] calldata addresses) external onlyOwner {
        for (uint256 i = 0; i < addresses.length; i++) {
            freeWhitelist[addresses[i]] = true;
        }
    }

    function addToPaidWhitelist(address[] calldata addresses) external onlyOwner {
        for (uint256 i = 0; i < addresses.length; i++) {
            paidWhitelist[addresses[i]] = true;
        }
    }

    function mintFreeWhitelistToken() external whenNotPaused onlyFreeWhitelisted {
        require(freeWhitelistMinted < FREE_WHITELIST_LIMIT, "Free whitelist sold out");
        freeWhitelistMinted++;
        _safeMint(msg.sender, freeWhitelistMinted);
    }

    function mintPaidWhitelistToken() external payable whenNotPaused onlyPaidWhitelisted {
        require(currentMintState == MintState.PostGenesis, "Not in post-genesis phase");
        require(paidWhitelistMinted < PAID_WHITELIST_LIMIT, "Paid whitelist sold out");
        require(msg.value >= 0.1 ether, "Insufficient payment");
        paidWhitelistMinted++;
        _safeMint(msg.sender, paidWhitelistMinted + FREE_WHITELIST_LIMIT);
    }

    function mintPublicToken() external payable whenNotPaused {
        require(currentMintState == MintState.PostGenesis, "Not in post-genesis phase");
        require(publicMinted < PUBLIC_MINT_LIMIT, "Public mint sold out");
        require(msg.value >= 0.2 ether, "Insufficient payment");
        publicMinted++;
        _safeMint(msg.sender, publicMinted + FREE_WHITELIST_LIMIT + PAID_WHITELIST_LIMIT);
    }

    function pause() external onlyOwner {
        _pause();
    }

    function unpause() external onlyOwner {
        _unpause();
    }

    function _baseURI() internal view override returns (string memory) {
        return baseURI;
    }

    function withdraw() external onlyOwner {
        address payable owner = payable(owner());
        owner.transfer(address(this).balance);
    }
}
