```solidity
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.4;

import "@openzeppelin/contracts/token/ERC721/extensions/ERC721URIStorage.sol";
import "@openzeppelin/contracts/security/Pausable.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/Counters.sol";

contract TokenContract is ERC721URIStorage, Pausable, Ownable {
    using Counters for Counters.Counter;

    enum MintState { Genesis, PostGenesis }
    enum WhitelistType { Free, Paid, Public }

    uint256 public constant FREE_WHITELIST_LIMIT = 1000;
    Counters.Counter private _tokenIdTracker;
    mapping(bytes32 => bool) private whitelist;

    bool private _mutex = false;

    modifier noReentrancy() {
        require(!_mutex, "No reentrancy");
        _mutex = true;
        _;
        _mutex = false;
    }

    modifier onlyValidStateTransition(MintState newState) {
        require(
            (block.number < genesisBlock && newState == MintState.Genesis) ||
            (block.number >= genesisBlock && newState == MintState.PostGenesis),
            "Invalid state transition"
        );
        _;
    }

    modifier onlyOwnerOrAdmin() {
        require(msg.sender == owner || msg.sender == admin, "Not owner or admin");
        _;
    }

    function safeMint(address to, uint256 tokenId, string memory uri) external onlyOwner {
        require(_mutex == false, "No reentrancy");
        _mutex = true;
        bool success = _mint(to, tokenId);
        require(success, "Mint failed");
        _setTokenURI(tokenId, uri);
        _mutex = false;
    }

